import{FileEntryCache}from"./util/file-entry-cache.js";import{timerify}from"./util/Performance.js";import{version}from"./version.js";const dummyFileDescriptor={key:"",changed:!0,notFound:!0};export class CacheConsultant{isEnabled;cache;constructor(e,i){if(this.isEnabled=i.isCache,this.isEnabled){const c=`${e.replace(/[^a-z0-9]/g,"-").replace(/-*$/,"")}-${i.isProduction?"-prod":""}-${version}`;this.cache=new FileEntryCache(c,i.cacheLocation),this.reconcile=timerify(this.cache.reconcile).bind(this.cache),this.getFileDescriptor=timerify(this.cache.getFileDescriptor).bind(this.cache)}}getFileDescriptor(e){return this.isEnabled&&this.cache?this.cache.getFileDescriptor(e):dummyFileDescriptor}reconcile(){this.isEnabled&&this.cache&&this.cache.reconcile()}}